//! Gold code sequence generator for spread spectrum watermarking.
//!
//! Gold codes are generated by XORing two maximal-length sequences (m-sequences)
//! with different phase offsets. They provide:
//!
//! - Three-valued cross-correlation: {-1, -t(n), t(n)-2} where t(n) = 2^((n+1)/2)+1
//! - Near-zero cross-correlation between different codes in the family
//! - Large code families: 2^n + 1 codes from n-bit shift registers
//!
//! This implementation uses LFSR-based m-sequences with preferred pair polynomials
//! for register lengths 5, 7, 9, and 10.

/// Gold code generator using two maximal-length LFSR sequences.
pub struct GoldCodeGenerator {
    /// Register length (number of bits).
    register_length: usize,
    /// Code period = 2^n - 1.
    period: usize,
    /// Feedback taps for first LFSR (polynomial 1).
    taps1: Vec<usize>,
    /// Feedback taps for second LFSR (polynomial 2).
    taps2: Vec<usize>,
}

/// LFSR state for m-sequence generation.
struct Lfsr {
    state: u32,
    taps: Vec<usize>,
    register_length: usize,
}

impl Lfsr {
    fn new(taps: &[usize], register_length: usize, seed: u32) -> Self {
        // Ensure non-zero initial state
        let state = if seed == 0 {
            1
        } else {
            seed & ((1 << register_length) - 1)
        };
        Self {
            state,
            taps: taps.to_vec(),
            register_length,
        }
    }

    /// Clock the LFSR one step, returning output bit (0 or 1).
    fn clock(&mut self) -> u8 {
        let output = (self.state & 1) as u8;

        // Compute feedback = XOR of tapped bits
        let mut feedback = 0u32;
        for &tap in &self.taps {
            feedback ^= (self.state >> tap) & 1;
        }

        self.state >>= 1;
        self.state |= feedback << (self.register_length - 1);

        output
    }

    /// Generate full period of m-sequence.
    fn generate_period(&mut self, period: usize) -> Vec<u8> {
        (0..period).map(|_| self.clock()).collect()
    }
}

impl GoldCodeGenerator {
    /// Create a Gold code generator with specified register length.
    ///
    /// Supported register lengths: 5, 7, 9, 10.
    /// Uses preferred pair polynomials for optimal cross-correlation.
    ///
    /// Returns `None` if the register length is not supported.
    #[must_use]
    pub fn new(register_length: usize) -> Option<Self> {
        let (taps1, taps2) = preferred_pair(register_length)?;
        let period = (1 << register_length) - 1;

        Some(Self {
            register_length,
            period,
            taps1,
            taps2,
        })
    }

    /// Generate a Gold code sequence of given length, using code_index to
    /// select which code in the Gold family (phase offset of second LFSR).
    ///
    /// `seed` controls the initial state of LFSR1.
    /// `code_index` selects the relative phase offset (0..period).
    ///
    /// Output: `Vec<i8>` with values +1 / -1.
    #[must_use]
    pub fn generate(&self, length: usize, seed: u64, code_index: usize) -> Vec<i8> {
        // Derive LFSR seeds from the provided seed
        let seed1 = ((seed & 0xFFFF_FFFF) as u32) | 1;
        let seed2 = (((seed >> 32) & 0xFFFF_FFFF) as u32) | 1;

        let mut lfsr1 = Lfsr::new(&self.taps1, self.register_length, seed1);
        let mut lfsr2 = Lfsr::new(&self.taps2, self.register_length, seed2);

        // Generate full period m-sequences
        let seq1 = lfsr1.generate_period(self.period);
        let seq2 = lfsr2.generate_period(self.period);

        // Apply phase offset to second sequence (cyclic shift)
        let offset = code_index % self.period;

        (0..length)
            .map(|i| {
                let idx = i % self.period;
                let idx2 = (idx + offset) % self.period;
                let bit = seq1[idx] ^ seq2[idx2];
                if bit == 0 {
                    1i8
                } else {
                    -1i8
                }
            })
            .collect()
    }

    /// Generate a Gold code with a simple seed-based interface (convenience method).
    ///
    /// Maps the seed deterministically to code_index and LFSR states.
    #[must_use]
    pub fn generate_from_seed(&self, length: usize, seed: u64) -> Vec<i8> {
        let code_index = (seed % self.period as u64) as usize;
        self.generate(length, seed, code_index)
    }

    /// Get the code period (= 2^n - 1).
    #[must_use]
    pub fn period(&self) -> usize {
        self.period
    }

    /// Get the Gold family size (= 2^n + 1).
    #[must_use]
    pub fn family_size(&self) -> usize {
        self.period + 2
    }

    /// Get the register length.
    #[must_use]
    pub fn register_length(&self) -> usize {
        self.register_length
    }

    /// Compute normalized cross-correlation between two Gold codes.
    #[must_use]
    pub fn cross_correlation(code_a: &[i8], code_b: &[i8]) -> f32 {
        let n = code_a.len().min(code_b.len());
        if n == 0 {
            return 0.0;
        }

        let sum: i64 = code_a
            .iter()
            .zip(code_b.iter())
            .take(n)
            .map(|(&a, &b)| i64::from(a) * i64::from(b))
            .sum();

        #[allow(clippy::cast_precision_loss)]
        let result = sum as f32 / n as f32;
        result
    }

    /// Compute auto-correlation at a given lag.
    #[must_use]
    pub fn auto_correlation(code: &[i8], lag: usize) -> f32 {
        let n = code.len();
        if lag >= n {
            return 0.0;
        }

        let sum: i64 = code
            .iter()
            .zip(code.iter().cycle().skip(lag))
            .take(n)
            .map(|(&a, &b)| i64::from(a) * i64::from(b))
            .sum();

        #[allow(clippy::cast_precision_loss)]
        let result = sum as f32 / n as f32;
        result
    }
}

/// Return preferred pair of LFSR tap positions for the given register length.
///
/// Returns `None` if no preferred pair is available for this length.
fn preferred_pair(n: usize) -> Option<(Vec<usize>, Vec<usize>)> {
    match n {
        5 => {
            // x^5 + x^2 + 1 and x^5 + x^4 + x^3 + x^2 + 1
            Some((vec![0, 2], vec![0, 2, 3, 4]))
        }
        7 => {
            // x^7 + x^3 + 1 and x^7 + x^3 + x^2 + x + 1
            Some((vec![0, 3], vec![0, 1, 2, 3]))
        }
        9 => {
            // x^9 + x^4 + 1 and x^9 + x^6 + x^4 + x^3 + 1
            Some((vec![0, 4], vec![0, 3, 4, 6]))
        }
        10 => {
            // x^10 + x^3 + 1 and x^10 + x^8 + x^3 + x^2 + 1
            Some((vec![0, 3], vec![0, 2, 3, 8]))
        }
        _ => None,
    }
}

/// Generate a Gold code sequence using the simplified interface.
///
/// Uses 5-bit register by default. For longer sequences, use `GoldCodeGenerator` directly.
#[must_use]
pub fn generate_gold_sequence(length: usize, seed: u64) -> Vec<i8> {
    // Choose register length based on desired sequence quality
    let reg_len = if length <= 31 {
        5
    } else if length <= 127 {
        7
    } else if length <= 511 {
        9
    } else {
        10
    };

    match GoldCodeGenerator::new(reg_len) {
        Some(gen) => gen.generate_from_seed(length, seed),
        None => {
            // Fallback: simple PN sequence
            crate::payload::generate_pn_sequence(length, seed)
        }
    }
}

#[cfg(test)]
#[allow(clippy::naive_bytecount)]
mod tests {
    use super::*;

    #[test]
    fn test_gold_code_generator_5bit() {
        let gen = GoldCodeGenerator::new(5).expect("5-bit should be supported");
        assert_eq!(gen.period(), 31);
        assert_eq!(gen.family_size(), 33);

        let code = gen.generate_from_seed(64, 12345);
        assert_eq!(code.len(), 64);
        assert!(code.iter().all(|&v| v == 1 || v == -1));
    }

    #[test]
    fn test_gold_code_generator_7bit() {
        let gen = GoldCodeGenerator::new(7).expect("7-bit should be supported");
        assert_eq!(gen.period(), 127);

        let code = gen.generate_from_seed(200, 99);
        assert_eq!(code.len(), 200);
    }

    #[test]
    fn test_gold_code_generator_9bit() {
        let gen = GoldCodeGenerator::new(9).expect("9-bit should be supported");
        assert_eq!(gen.period(), 511);
    }

    #[test]
    fn test_gold_code_generator_10bit() {
        let gen = GoldCodeGenerator::new(10).expect("10-bit should be supported");
        assert_eq!(gen.period(), 1023);
    }

    #[test]
    fn test_unsupported_register_length() {
        assert!(GoldCodeGenerator::new(3).is_none());
        assert!(GoldCodeGenerator::new(4).is_none());
        assert!(GoldCodeGenerator::new(11).is_none());
    }

    #[test]
    fn test_deterministic_generation() {
        let gen = GoldCodeGenerator::new(7).expect("should succeed");

        let code1 = gen.generate_from_seed(128, 42);
        let code2 = gen.generate_from_seed(128, 42);
        assert_eq!(code1, code2);

        let code3 = gen.generate_from_seed(128, 43);
        assert_ne!(code1, code3);
    }

    #[test]
    fn test_auto_correlation_peak() {
        let gen = GoldCodeGenerator::new(7).expect("should succeed");
        let code = gen.generate_from_seed(127, 1);

        // Auto-correlation at lag 0 should be 1.0
        let ac0 = GoldCodeGenerator::auto_correlation(&code, 0);
        assert!((ac0 - 1.0).abs() < 0.01, "ac(0) = {ac0}");

        // Auto-correlation at other lags should be much lower
        for lag in 1..10 {
            let ac = GoldCodeGenerator::auto_correlation(&code, lag);
            assert!(ac.abs() < 0.3, "ac({lag}) = {ac}, should be near zero");
        }
    }

    #[test]
    fn test_cross_correlation_low() {
        let gen = GoldCodeGenerator::new(7).expect("should succeed");

        // Two different codes in the Gold family
        let code_a = gen.generate(127, 1, 0);
        let code_b = gen.generate(127, 1, 5);

        let cc = GoldCodeGenerator::cross_correlation(&code_a, &code_b);
        assert!(cc.abs() < 0.3, "cross-correlation = {cc}, should be low");
    }

    #[test]
    fn test_cross_correlation_different_seeds() {
        let gen = GoldCodeGenerator::new(9).expect("should succeed");

        let code_a = gen.generate_from_seed(256, 100);
        let code_b = gen.generate_from_seed(256, 200);

        let cc = GoldCodeGenerator::cross_correlation(&code_a, &code_b);
        assert!(cc.abs() < 0.3, "cross-correlation = {cc}");
    }

    #[test]
    fn test_gold_vs_pn_cross_correlation() {
        // Gold codes should have better cross-correlation properties than basic PN
        let gen = GoldCodeGenerator::new(7).expect("should succeed");
        let length = 127;

        // Generate multiple Gold codes and measure max cross-correlation
        let mut max_gold_cc = 0.0f32;
        let codes: Vec<Vec<i8>> = (0..10).map(|i| gen.generate(length, 1, i * 3)).collect();

        for i in 0..codes.len() {
            for j in (i + 1)..codes.len() {
                let cc = GoldCodeGenerator::cross_correlation(&codes[i], &codes[j]).abs();
                if cc > max_gold_cc {
                    max_gold_cc = cc;
                }
            }
        }

        // Generate PN codes and measure max cross-correlation
        let mut max_pn_cc = 0.0f32;
        let pn_codes: Vec<Vec<i8>> = (0..10)
            .map(|i| crate::payload::generate_pn_sequence(length, i as u64 * 1000))
            .collect();

        for i in 0..pn_codes.len() {
            for j in (i + 1)..pn_codes.len() {
                let cc = GoldCodeGenerator::cross_correlation(&pn_codes[i], &pn_codes[j]).abs();
                if cc > max_pn_cc {
                    max_pn_cc = cc;
                }
            }
        }

        // Gold codes should have lower or comparable max cross-correlation
        // (allowing some tolerance since PN sequences can sometimes be lucky)
        assert!(
            max_gold_cc < max_pn_cc + 0.15,
            "Gold max cc = {max_gold_cc}, PN max cc = {max_pn_cc}"
        );
    }

    #[test]
    fn test_generate_gold_sequence_convenience() {
        let seq_short = generate_gold_sequence(20, 42);
        assert_eq!(seq_short.len(), 20);

        let seq_medium = generate_gold_sequence(100, 42);
        assert_eq!(seq_medium.len(), 100);

        let seq_long = generate_gold_sequence(300, 42);
        assert_eq!(seq_long.len(), 300);

        let seq_very_long = generate_gold_sequence(600, 42);
        assert_eq!(seq_very_long.len(), 600);
    }

    #[test]
    fn test_lfsr_m_sequence_properties() {
        // An m-sequence of period 2^n - 1 should have (2^(n-1)) ones and (2^(n-1) - 1) zeros
        let gen = GoldCodeGenerator::new(5).expect("should succeed");
        let mut lfsr = Lfsr::new(&gen.taps1, gen.register_length, 1);
        let seq = lfsr.generate_period(gen.period);

        let ones: usize = seq.iter().filter(|&&b| b == 1).count();
        let zeros: usize = seq.iter().filter(|&&b| b == 0).count();

        // For n=5, period=31: expect 16 ones and 15 zeros
        assert_eq!(ones, 16, "expected 16 ones, got {ones}");
        assert_eq!(zeros, 15, "expected 15 zeros, got {zeros}");
    }

    #[test]
    fn test_gold_code_balanced() {
        let gen = GoldCodeGenerator::new(7).expect("should succeed");
        let code = gen.generate_from_seed(127, 77);

        let plus_ones = code.iter().filter(|&&v| v == 1).count();
        let minus_ones = code.iter().filter(|&&v| v == -1).count();

        // Gold codes should be approximately balanced
        let diff = (plus_ones as i64 - minus_ones as i64).unsigned_abs();
        assert!(diff < 20, "unbalanced: +1={plus_ones}, -1={minus_ones}");
    }

    #[test]
    fn test_different_code_indices_produce_different_codes() {
        let gen = GoldCodeGenerator::new(7).expect("should succeed");

        let code0 = gen.generate(127, 1, 0);
        let code1 = gen.generate(127, 1, 1);
        let code2 = gen.generate(127, 1, 2);

        assert_ne!(code0, code1);
        assert_ne!(code1, code2);
        assert_ne!(code0, code2);
    }
}
